control_475 = readmatrix("control_475.csv") %[output:5f452411]
finger_475 = readmatrix("finger_475.csv") %[output:9434c723]
finger_LED_475 = readmatrix("finger_LED_475.csv") %[output:6144b589]

c4t = fft(control_475) %[output:148f9d10]
f4t = fft(finger_475) %[output:075af18a]
fL4t = fft(finger_LED_475) %[output:3348f700]
%%
plot(abs(c4t)) %[output:3ad96c3e]
hold on %[output:3ad96c3e]
plot(abs(f4t)) %[output:3ad96c3e]
plot(abs(fL4t)) %[output:3ad96c3e]
legend("c4t Base","c4t Cap","f4t Base","f4t Cap","fl4t Base","fl4t Cap") %[output:3ad96c3e]
hold off %[output:3ad96c3e]
%%
ct = abs(c4t) %[output:5eb286fe]
ct = ct(:,1) %[output:56dd326a]
ft = abs(f4t) %[output:8056bebe]
ft = ft(:,1) %[output:3b083f33]
flt = abs(fL4t) %[output:894f0642]
flt = flt(:,1) %[output:1386efea]
plot(ct) %[output:900dea0f]
hold on %[output:900dea0f]
plot(ft) %[output:900dea0f]
plot(flt) %[output:900dea0f]
legend("ct","ft","flt") %[output:900dea0f]
hold off %[output:900dea0f]

